import{_ as a,o as e,c as t,ai as s}from"./chunks/framework.CzqNhXfh.js";const m=JSON.parse('{"title":"我的2022","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"essays/articles/article-009.md","filePath":"essays/articles/article-009.md","lastUpdated":1776825361000}'),r={name:"essays/articles/article-009.md"};function o(c,p,l,i,_,n){return e(),t("div",null,[...p[0]||(p[0]=[s('<h1 id="我的2022" tabindex="-1">我的2022 <a class="header-anchor" href="#我的2022" aria-label="Permalink to &quot;我的2022&quot;">​</a></h1><blockquote><p>子昱 闲谈之余 2022年12月31日 23:51 江西</p></blockquote><p>咔！静下来</p><p>又是一年，马上2023了。每一年的尾声时都觉得后一年的到来是自然的，顺理成章的。可是又好不自然，2003-2023。我已经快20岁了——我心中的成人之龄。可是我才大二呀，我只是个学生，我竟然还是个学生，涉世未深，接受吧，这是你。</p><p>我的2022，一眼扫去，寒假+大一下+暑假+大二上</p><p>一目了然</p><p>时间其实过得很慢，原来很多我以为发生了很久的事情，其实就在今年</p><p>寒假的前端学习，滑雪之旅，开学的封控......</p><p>哇！哦，它们真的在2022。</p><p>时间过得很快，每周总有忙不完的事和忙不完的事。总是在路上。大二开学时，我在班级总结上说，不要高估自己的执行力，有什么事就要当下去做，立即开始。我明白得很。可有些时候，你明白，你又不去做。还是说得漂亮，事情却差强人意，不是吗？</p><p>忙是对的，别让自己太悠闲了。但是，坐在自习室里的你心安理得吗？你的效率有时令人发笑。话说得重了些，但事实如此。你已经很难做到高中时期的全身心投入。手机、电脑，各种消息向你袭来，但其实这不是理由，你只是不愿做，不愿改。该怪谁呢？大学环境的静默摧残？不可否认，影响很大。</p><p>你很想向张可意学姐，无不敬佩她的规划与落地。</p><p>花花世界迷人眼，你很难抵抗，但你必须抵抗。苦厄艰难的时刻是你成长最快的瞬间。太多事咯，简单易行，娱乐还是娱乐，它们朝你发出无限引力，你一边惶恐恐入其中，一边被一点点拽近，生动写照是吗？</p><p>说过很多遍的事，自制力不够。不要高估自己。但这不是你轻浮躺下的理由。</p><p>很难，我知道很难，但能不能加油？</p><p>明天是2023.1.1，新年伊始，新的开始，对的吧？</p><p>明年也是四年中最关键的一年，拼搏自不必说！</p><p>说了这么多反省的，也来讲讲经历的事吧，现在我的脑海中从一月开始翻起，讲讲记忆深刻的：</p><p>寒假新年，逼迫着自己学习网页前端，现在回想，有些佩服自己的毅力，或许这就是前面有人领着学的好处吧。</p><p>大一下先是无端的忙碌和agv。</p><p>暑假是驾照和后端的时光，认识了一群不认识的人，哈哈，莫名的喜悦。</p><p>6-9月还有，她她她。避不开的一段经历，我不知道说什么。我犯了很多错，但这段经历仍然不后悔，同样她我学到了很多。感谢，真心感谢。疯狂的一吻，刻骨铭心，定难相忘。那段时间的心乱如麻，胡思乱想。和她讲明白所有的事情前后......... 最后不了了之，草草结尾。我现在是怀着很平淡的心情去回忆，那时的绝望与苦恼已烟消云散。所以，不要把自己想得太深情？你其实很一般。这是直白的叙述，是承认所有。</p><p>想清楚之后，本科大概很难再遇上一个人能一直走下去吧，我想。现实主义还是占了上风。</p><p>不同的人持有不同观点，秦老师是绝对的抵制者：谈恋爱就是浪费时间啊！</p><p>我不会听从长远未来的角度考虑，很可能是这样；但我心存一份青春浪潮浪漫激情的纯真，不愿加以排斥。人的思考若只剩下了现实，那么荒芜也会随之而来吧</p><p>大二没有一个开心的开局。抛开所谓伤痛，投入其他事务，再到12月全面开放，早早返乡。一切都很匆忙，匆忙到真的不知道做了什么。</p><p>12月，伤历历在目，是你颓废的。比你预料之中还要糟糕一些。</p><p>还来得及吧！</p><p>欢愉的总是不如折磨的！</p><p>2023要来咯！</p>',30)])])}const u=a(r,[["render",o]]);export{m as __pageData,u as default};
